ap_cuhk_tbl_3_2:"Basic items + thyroid function, tumour markers (5 items), abdominal ultrasound, ECG",
ap_cuhk_tbl_3_3:"~3 hours",
ap_cuhk_tbl_3_4:"HKD 8,800",
ap_cuhk_tbl_4_1:"Comprehensive Health Check",
