ap_sgcost_tbl_1_21:"120 - 200",
ap_sgcost_p_5:"The above are consultation fees only and do not include any examination, testing, or treatment costs.",
ap_sgcost_h3_2:"Common Examination Costs",
ap_sgcost_p_6:"Below are approximate costs of common examinations at Singapore private hospitals (SGD):",
ap_sgcost_ul1_1:"Complete Blood Count: 80 - 150",
ap_sgcost_ul1_2:"Comprehensive Metabolic Panel: 200 - 400",
ap_sgcost_ul1_3:"Tumor Marker Test: 150 - 500 (depending on number of markers)",
ap_sgcost_ul1_4:"Abdominal Ultrasound: 300 - 600",
ap_sgcost_ul1_5:"Echocardiogram: 500 - 900",
ap_sgcost_ul1_6:"Chest CT (non-contrast): 600 - 1,200",
ap_sgcost_ul1_7:"Full Abdominal CT (contrast-enhanced): 1,000 - 2,000",
ap_sgcost_ul1_8:"MRI (single region): 800 - 1,800",
ap_sgcost_ul1_9:"PET-CT Whole Body: 2,000 - 3,500",
ap_sgcost_ul1_10:"Colonoscopy: 1,500 - 3,000",
ap_sgcost_ul1_11:"Gastroscopy: 1,200 - 2,500",
ap_sgcost_h2_3:"III. Inpatient Costs",
ap_sgcost_p_7:"Inpatient costs at Singapore private hospitals mainly consist of the following components: bed charges, nursing fees, doctor's round fees, medication costs, and miscellaneous fees. Bed charges vary the most.",
ap_sgcost_h3_3:"Ward Charges",
ap_sgcost_tbl_2_1:"Room Type",
ap_sgcost_tbl_2_2:"Cost (SGD/night)",
ap_sgcost_tbl_2_3:"General Ward (4-6 beds)",
ap_sgcost_tbl_2_4:"200 - 400",
